PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE products (
      slug TEXT PRIMARY KEY,
      title TEXT NOT NULL,
      subtitle TEXT,
      price TEXT,
      image_url TEXT,
      first_seen_at TEXT NOT NULL,
      last_seen_at TEXT NOT NULL
    );
CREATE TABLE product_categories (
      product_slug TEXT NOT NULL REFERENCES products(slug),
      category_key TEXT NOT NULL,
      PRIMARY KEY (product_slug, category_key)
    );
CREATE TABLE product_attributes (
      product_slug TEXT NOT NULL,
      attribute_type TEXT NOT NULL,
      attribute_value TEXT NOT NULL,
      PRIMARY KEY (product_slug, attribute_type, attribute_value)
    );
CREATE TABLE product_occasion (
      product_slug TEXT PRIMARY KEY,
      occasion TEXT NOT NULL,
      classified_at TEXT NOT NULL
    , source TEXT NOT NULL DEFAULT 'llm', confidence REAL, review_status TEXT NOT NULL DEFAULT 'needs-llm-review', reason TEXT, evidence_json TEXT, reviewer_confidence REAL, reviewer_reason TEXT, reviewed_at TEXT);
COMMIT;
